import { Component, OnInit } from '@angular/core';
import { BookService } from '../../services/book.service';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-book-search',
  templateUrl: './book-search.component.html',
  styleUrls: ['./book-search.component.css']
})
export class BookSearchComponent implements OnInit {
  books: any[] = [];
  filteredBooks: any[] = [];
  isLoading: boolean = false;

  searchFilters = {
    title: '',
    author: '',
    category: ''
  };

  categories: string[] = [
    'Programming', 'Software Engineering', 'Database', 'Web Development',
    'Mobile Development', 'Data Science', 'Artificial Intelligence',
    'Computer Science', 'Mathematics', 'Physics', 'Chemistry',
    'Biology', 'Literature', 'History', 'Other'
  ];

  currentUser: any = null;

  constructor(private bookService: BookService, private authService: AuthService) {}

  ngOnInit(): void {
    this.currentUser = this.authService.getCurrentUser();
    this.loadBooks();
  }

  loadBooks(): void {
    this.books = this.bookService.getBooks();
    this.filteredBooks = [...this.books];
  }

  searchBooks(): void {
    this.filteredBooks = this.bookService.searchBooks(this.searchFilters);
  }

  clearFilters(): void {
    this.searchFilters = {
      title: '',
      author: '',
      category: ''
    };
    this.filteredBooks = [...this.books];
  }

  issueBook(book: any): void {
    if (!this.currentUser) {
      alert('Please login to issue books');
      return;
    }

    if (book.availableQuantity <= 0) {
      alert('This book is not available for issuing');
      return;
    }

    const result = this.bookService.issueBook(book.id, this.currentUser.id);

    if (result.success) {
      alert(result.message);
      this.loadBooks();
    } else {
      alert(result.message);
    }
  }

  getAvailabilityStatus(book: any): string {
    if (book.availableQuantity === 0) {
      return 'Not Available';
    } else if (book.availableQuantity < book.quantity * 0.2) {
      return 'Limited Copies';
    } else {
      return 'Available';
    }
  }

  getAvailabilityClass(book: any): string {
    if (book.availableQuantity === 0) {
      return 'not-available';
    } else if (book.availableQuantity < book.quantity * 0.2) {
      return 'limited';
    } else {
      return 'available';
    }
  }

  isAdmin(): boolean {
    return this.authService.isAdmin();
  }
}
<div class="book-search-container">
  <div class="page-header">
    <h1>🔍 Search Books</h1>
    <p>Find and search books in the library</p>
  </div>

  <!-- Search Filters -->
  <div class="search-filters">
    <div class="filter-card">
      <h3>Search Filters</h3>

      <div class="filter-row">
        <div class="form-group">
          <label for="title">Book Title</label>
          <input 
            type="text" 
            id="title" 
            name="title" 
            [(ngModel)]="searchFilters.title" 
            (input)="searchBooks()"
            placeholder="Enter book title..."
          />
        </div>

        <div class="form-group">
          <label for="author">Author</label>
          <input 
            type="text" 
            id="author" 
            name="author" 
            [(ngModel)]="searchFilters.author" 
            (input)="searchBooks()"
            placeholder="Enter author name..."
          />
        </div>

        <div class="form-group">
          <label for="category">Category</label>
          <select 
            id="category" 
            name="category" 
            [(ngModel)]="searchFilters.category" 
            (change)="searchBooks()"
          >
            <option value="">All Categories</option>
            <option *ngFor="let category of categories" [value]="category">
              {{ category }}
            </option>
          </select>
        </div>
      </div>

      <div class="filter-actions">
        <button class="clear-btn" (click)="clearFilters()">Clear Filters</button>
        <div class="results-count">
          Found {{ filteredBooks.length }} books
        </div>
      </div>
    </div>
  </div>

  <!-- Books Grid -->
  <div class="books-section">
    <div *ngIf="filteredBooks.length === 0" class="empty-state">
      <div class="empty-icon">📚</div>
      <h3>No books found</h3>
      <p>Try adjusting your search filters or check back later for new additions.</p>
    </div>

    <div class="books-grid" *ngIf="filteredBooks.length > 0">
      <div *ngFor="let book of filteredBooks" class="book-card">
        <div class="book-header">
          <h3 class="book-title">{{ book.title }}</h3>
          <span class="availability-badge" [ngClass]="getAvailabilityClass(book)">
            {{ getAvailabilityStatus(book) }}
          </span>
        </div>

        <div class="book-details">
          <div class="book-info">
            <p class="author">📝 {{ book.author }}</p>
            <p class="category">🏷️ {{ book.category }}</p>
          </div>

          <div class="book-quantity">
            <div class="quantity-info">
              <span class="available">{{ book.availableQuantity }}</span>
              <span class="separator">/</span>
              <span class="total">{{ book.quantity }}</span>
            </div>
            <p class="quantity-label">Available</p>
          </div>
        </div>

        <div class="book-actions">
          <button 
            class="issue-btn" 
            (click)="issueBook(book)"
            [disabled]="book.availableQuantity === 0"
            *ngIf="!isAdmin()"
          >
            <span *ngIf="book.availableQuantity > 0">📖 Issue Book</span>
            <span *ngIf="book.availableQuantity === 0">❌ Not Available</span>
          </button>

          <div class="admin-actions" *ngIf="isAdmin()">
            <span class="admin-note">Admin: Use Book Management to edit</span>
          </div>
        </div>

        <div class="book-footer">
          <small class="added-date">
            Added on {{ book.addedDate | date:'mediumDate' }}
          </small>
        </div>
      </div>
    </div>
  </div>
</div>
